/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `trau_feedbackratingcount` AFTER UPDATE ON `tbl_feedbackratingcount` FOR EACH ROW begin
DECLARE RATING INT;
 SET RATING = new.frc_5star+ new.frc_4star  +new.frc_3star+new.frc_2star+new.frc_1star;
