 BEGIN
   UPDATE tbl_menumaster set  mr_rating = (((5*new.frc_5star)+(4*new.frc_4star)+(3*new.frc_3star)+(2*new.frc_2star)+(1*new.frc_1star)) /RATING) where mr_menuid = new.frc_menuid;
  END;
  END IF;
end */;;
