  `mr_unit_type` varchar(30) COLLATE utf8_unicode_ci DEFAULT NULL,
  `mr_base_unit` int(11) DEFAULT NULL,
  `mr_add_on` char(1) COLLATE utf8_unicode_ci NOT NULL DEFAULT 'N',
