  `mr_qr_set` char(1) COLLATE utf8_unicode_ci NOT NULL DEFAULT 'Y',
  `mr_delete_mode` char(1) COLLATE utf8_unicode_ci NOT NULL DEFAULT 'N',
  `mr_central_id` varchar(250) COLLATE utf8_unicode_ci DEFAULT NULL,
