/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `trai_menumaster` AFTER INSERT ON `tbl_menumaster` FOR EACH ROW begin
UPDATE `tbl_appmachinedetails` SET `as_sync_menumaster` = 'Y';
INSERT INTO `tbl_feedbackratingcount`(`frc_menuid`) VALUES(new.mr_menuid);
END */;;
