/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `trbu_menuratemaster` BEFORE UPDATE ON `tbl_menuratemaster` FOR EACH ROW BEGIN DECLARE SYNCH CHAR(1); 
SET SYNCH ='Y'; 
IF(old.cloud_sync != 'N')THEN
SET new.cloud_sync = 'N';
END IF;
IF(NEW.mmr_android_sync != OLD.mmr_android_sync) THEN 
BEGIN 
	IF(NEW.mmr_android_sync = 'N') THEN 
	SET SYNCH ='N'; 
    END IF; 
END; 
END IF; 
IF(SYNCH ='Y') THEN
BEGIN 
	SET NEW.mmr_android_sync = 'Y'; 
 	update tbl_appmachinedetails set as_sync_menuratemaster='Y';
END;
ELSE 
SET NEW.mmr_android_sync = 'N';
END IF; 
END */;;
