CREATE DEFINER=`root`@`%` PROCEDURE `proc_menu_import`(OUT `Message` VARCHAR(100), IN `RATE_1_FOR` VARCHAR(30), IN `RATE_2_FOR` VARCHAR(30), IN `RATE_3_FOR` VARCHAR(30), IN `RATE_4_FOR` VARCHAR(30), IN `RATE_5_FOR` VARCHAR(30))
