  INSERT INTO `tbl_printersettings`(`pr_id`, `pr_printername`, `pr_printerip`, `pr_printerport`, `pr_branchid`, `pr_printertype`, `pr_style`) 
  VALUES(0,'CS BILL','192.168.1.88','9100',1,11,1);
  INSERT INTO `tbl_printersettings`(`pr_id`, `pr_printername`, `pr_printerip`, `pr_printerport`, `pr_branchid`, `pr_printertype`, `pr_style`) 
  VALUES(0,'REPORT', '192.168.1.88', '9100', 1, 3,1);
END ;;
