UPDATE tbl_year_bill_series SET  b_count = 1 WHERE b_fin_year = (SELECT ys_fin_year FROM tbl_yearsettings WHERE ys_fin_year_current= 'Y');
UPDATE `tbl_year_bill_series` SET`b_count` = 1;
  SET FOREIGN_KEY_CHECKS = 1;
END ;;
