   IF(PORTION IS NULL)THEN
    SET  PORTION = 0;
   END IF;
   call proc_menustock_entry(menuid,ratetype,PORTION,unit_type,weight,unit_id,base_unit_id);
  END LOOP;
 CLOSE cur1;
END ;;
