    NO SQL
BEGIN
    set message  = 'Error';
    INSERT INTO `tbl_temp_tablebillmaster`(`bm_temp_billno`, `bm_main_billno`, `bm_branchid`, `bm_floorid`, `bm_subtotal`,  `bm_dayclosedate`, `bm_tableno`) 
